form:Form.form:Scripts:
		function disable_custom_buttons()
{
	CtrlEnabled("CONC_MAN_PER"       , false);
	CtrlEnabled("VAL_VAREN"          , false);

	CtrlEnabled("VAL_VAREF_EDIT"     , false);
	CtrlEnabled("VAL_VAREA_EDIT"     , false);
	CtrlEnabled("VAL_VAREN_EDIT"     , false);
	CtrlEnabled("VAL_VAREN_EDIT_VALOR"     , false);
	CtrlEnabled("VAL_VARCM_EDIT"     , false);
	CtrlEnabled("VAL_VARPA_EDIT"     , false);
	CtrlEnabled("VAL_VARPN_EDIT"     , false);	

	CtrlEnabled("VER_RECIBO"         , false);
	CtrlEnabled("VER_RECIBO_COMPLETO", false);
	CtrlEnabled("VER_LEGAJO"         , false);
	CtrlEnabled("VER_LEGAJO_CERRADO" , false);
	CtrlEnabled("EDIT"               , false);
	CtrlEnabled('VER_LEGAJO_CERRADO' , false);
	CtrlEnabled('COMENTARIO_EDIT'    , false);
}

function enable_custom_buttons()
{
	// Habilita cuando hay registro seleccionado
	var ena=Ctrl("listFILTER").GetXValue()!=""?true:false;


	if (Ctrl("listFILTER").GetXValue()=="")
	{
		CtrlEnabled("CONC_MAN_PER"       , false);
		CtrlEnabled("VAL_VAREN"          , false);

		CtrlEnabled("VAL_VAREF_EDIT"     , false);
		CtrlEnabled("VAL_VAREA_EDIT"     , false);
		CtrlEnabled("VAL_VAREN_EDIT"     , false);
		CtrlEnabled("VAL_VAREN_EDIT_VALOR"     , false);
		CtrlEnabled("VAL_VARCM_EDIT"     , false);
		CtrlEnabled("VAL_VARPA_EDIT"     , false);
		CtrlEnabled("VAL_VARPN_EDIT"     , false);	

		CtrlEnabled("VER_RECIBO"         , false);
		CtrlEnabled("VER_RECIBO_COMPLETO", false);
		CtrlEnabled("VER_LEGAJO"         , false);
		CtrlEnabled("VER_LEGAJO_CERRADO" , false);
		CtrlEnabled("EDIT"               , false);
		CtrlEnabled('VER_LEGAJO_CERRADO' , false);
		CtrlEnabled('COMENTARIO_EDIT'    , false);
	} else
	if (Ctrl('c_estado_liq').GetXValue()=="C")  
	{
		CtrlEnabled("CONC_MAN_PER"       , true);
		CtrlEnabled("VAL_VAREN"          , true);

		CtrlEnabled('VAL_VAREN_EDIT'     , false);
		CtrlEnabled("VAL_VAREN_EDIT_VALOR"     , false);
		CtrlEnabled('VAL_VARCM_EDIT'     , false);
		CtrlEnabled('VAL_VAREF_EDIT'     , false);
		CtrlEnabled('VAL_VAREA_EDIT'     , false);
		CtrlEnabled('VAL_VARPA_EDIT'     , false);
		CtrlEnabled('VAL_VARPN_EDIT'     , false);
		CtrlEnabled('COMENTARIO_EDIT'    , true);

		CtrlEnabled("VER_RECIBO"         , true);
		CtrlEnabled("VER_RECIBO_COMPLETO", true);
		CtrlEnabled("VER_LEGAJO"         , false);
		CtrlEnabled("VER_LEGAJO_CERRADO" , false);
		CtrlEnabled("EDIT"               , false);
		CtrlEnabled('VER_LEGAJO_CERRADO' , true);
	} else
	if (Ctrl("listFILTER").GetSelectAttrValue("ESTADO")=="C")
	{
		CtrlEnabled("CONC_MAN_PER"       , true);
		CtrlEnabled("VAL_VAREN"          , true);

		CtrlEnabled("VAL_VAREF_EDIT"     , false);
		CtrlEnabled("VAL_VAREA_EDIT"     , false);
		CtrlEnabled("VAL_VAREN_EDIT"     , false);
		CtrlEnabled("VAL_VAREN_EDIT_VALOR"     , false);
		CtrlEnabled("VAL_VARCM_EDIT"     , false);
		CtrlEnabled("VAL_VARPA_EDIT"     , false);
		CtrlEnabled("VAL_VARPN_EDIT"     , false);	
		CtrlEnabled('COMENTARIO_EDIT'    , true);

		CtrlEnabled("VER_RECIBO"         , true);
		CtrlEnabled("VER_RECIBO_COMPLETO", true);
		CtrlEnabled("VER_LEGAJO"         , false);
		CtrlEnabled("VER_LEGAJO_CERRADO" , false);
		CtrlEnabled("EDIT"               , false);
		CtrlEnabled('VER_LEGAJO_CERRADO' , true);
	} else
	if (Ctrl("listFILTER").GetSelectAttrValue("ESTADO")=="R")
	{
		CtrlEnabled("CONC_MAN_PER"       , true);
		CtrlEnabled("VAL_VAREN"          , true);

		CtrlEnabled("VAL_VAREF_EDIT"     , true);
		CtrlEnabled("VAL_VAREA_EDIT"     , true);
		CtrlEnabled("VAL_VAREN_EDIT"     , true);
		CtrlEnabled("VAL_VAREN_EDIT_VALOR"     , true);
		CtrlEnabled("VAL_VARCM_EDIT"     , true);
		CtrlEnabled("VAL_VARPA_EDIT"     , true);
		CtrlEnabled("VAL_VARPN_EDIT"     , true);
		CtrlEnabled('COMENTARIO_EDIT'    , true);	

		CtrlEnabled("VER_RECIBO"         , true);
		CtrlEnabled("VER_RECIBO_COMPLETO", true);
		CtrlEnabled("VER_LEGAJO"         , true);
		CtrlEnabled("VER_LEGAJO_CERRADO" , true);
		CtrlEnabled("EDIT"               , true);
		CtrlEnabled('VER_LEGAJO_CERRADO' , false);
	} else
	{
		CtrlEnabled("CONC_MAN_PER"       , true);
		CtrlEnabled("VAL_VAREN"          , true);

		CtrlEnabled("VAL_VAREF_EDIT"     , true);
		CtrlEnabled("VAL_VAREA_EDIT"     , true);
		CtrlEnabled("VAL_VAREN_EDIT"     , true);
		CtrlEnabled("VAL_VAREN_EDIT_VALOR"     , true);
		CtrlEnabled("VAL_VARCM_EDIT"     , true);
		CtrlEnabled("VAL_VARPA_EDIT"     , true);
		CtrlEnabled("VAL_VARPN_EDIT"     , true);	
		CtrlEnabled('COMENTARIO_EDIT'    , true);

		CtrlEnabled("VER_RECIBO"         , false);
		CtrlEnabled("VER_RECIBO_COMPLETO", false);
		CtrlEnabled("VER_LEGAJO"         , true);
		CtrlEnabled("VER_LEGAJO_CERRADO" , true);
		CtrlEnabled("EDIT"               , true);
		CtrlEnabled('VER_LEGAJO_CERRADO' , false);
	}
}


function ONLOAD_custom()
{                     
	Ctrl("where").SetXValue("LEG.oi_personal_emp in (SELECT LIQ25_PERSONAL_LIQ.oi_personal_emp FROM LIQ25_PERSONAL_LIQ WHERE LIQ25_PERSONAL_LIQ.oi_liquidacion = "+Ctrl("liquidacion").GetXValue()+")");

	if(!Ctrl('img_ojo').GetEnabled())
	{
		Ctrl('cb_confidenciales').SetXValue('NC');
	}   
	else
	{
		Ctrl('cb_confidenciales').SetXValue('T');
	}
}

function EDIT_VAL_VAREN()
{
	openNewFlowWait("NucleusRH.Base.Liquidacion.Variables.VariablesNoPersona.flow","initialize",'<DATA oi="'+Ctrl("listFILTER").GetSelectAttrValue("oi_personal_liq")+'"/>', new ObjtectResult(),"L");
}
function EDIT_VAL_VAREN_VALOR()
{
	openNewFlowWait("NucleusRH.Base.Liquidacion.Variables.VariablesNoPersona.flow","VariablesValores",'<DATA oi="'+Ctrl("listFILTER").GetSelectAttrValue("oi_personal_liq")+'"/>', new ObjtectResult(),"L");
}
function EDIT_VAL_VARCM()
{
	openNewFlowWait("NucleusRH.Base.Liquidacion.Variables.VariablesNoPersona.flow","conceptos",'<DATA oi="'+Ctrl("listFILTER").GetSelectAttrValue("oi_personal_liq")+'"/>', new ObjtectResult(),"L");
}
function EDIT_VAL_VARPN()
{                                                 
	openNewFlowWait("NucleusRH.Base.Liquidacion.Variables.VariablesNRPersona.flow","initialize",'<DATA oi="'+Ctrl("listFILTER").GetSelectAttrValue("oi_personal_liq")+'"/>', new ObjtectResult(),"L");
}
function CALL_VAL_VARPA()
{
	openNewFlowWait("NucleusRH.Base.Liquidacion.Variables.VariablesAPPersona.flow","initialize",'<DATA oi="'+Ctrl("listFILTER").GetXValue()+'"/>', new ObjtectResult(),"L");
}
function VER_RECIBO()
{  
 	parent.ShowREPORT("NucleusRH.Base.Liquidacion.Recibo.rpt","oi_personal_liq="+Ctrl("listFILTER").GetSelectAttrValue("oi_personal_liq"));
}
function VER_RECIBO_COMPLETO()
{
 	parent.ShowREPORT("NucleusRH.Base.Liquidacion.ReciboCompleto.rpt","oi_personal_liq="+Ctrl("listFILTER").GetSelectAttrValue("oi_personal_liq"));
}
function VER_LEGAJO()
{
	openNewFlowWait("NucleusRH.Base.Liquidacion.Reporte.LegajoLiquidacion.flow","initializeDesde25","<PARAMETERS oi_personal_emp=\""+Ctrl("listFILTER").GetXValue()+"\" />",new ObjtectResult(),"L");
}     
function VER_LEGAJO_CERRADO()
{
	openNewFlowWait("NucleusRH.Base.Liquidacion.Reporte.LegajoLiquidacion.Cerradas.flow","initializeDesde25","<datos oi_personal_liq=\""+Ctrl("listFILTER").GetSelectAttrValue("oi_personal_liq")+"\" />",new ObjtectResult(),"L");
}

function set_oi()
{
	Ctrl("oi_personal_liq").SetXValue(Ctrl("listFILTER").GetSelectAttrValue("oi_personal_liq"));
	Ctrl("oi_personal_emp").SetXValue(Ctrl("listFILTER").GetXValue());
}
function CALL_CONC_MAN_PER()
{
	set_oi();
	Ctrl('main').DoEvent('CALL:CONC_MAN_PER');
}
function CALL_VAL_VAREN()
{
	set_oi();
	Ctrl('main').DoEvent('CALL:VAL_VAREN');
}
function EDIT()
{
	set_oi();
	Ctrl('main').DoEvent('EDIT');
}

function ObjtectResult()
{
	this.processResult= function(xmlin){}
}

function CALL_VAL_VAREF()
{
	openNewFlowWait("NucleusRH.Base.Liquidacion.Variables.VariablesFiPersona.flow","initialize",'<DATA oi="'+Ctrl("listFILTER").GetXValue()+'"/>', new ObjtectResult(),"L");
}

function CALL_COMENTARIOS()
{
	openNewFlowWait("NucleusRH.Base.Liquidacion.Comentarios_Liquidacion.flow","initialize",'<DATA oi="'+Ctrl("listFILTER").GetXValue()+'" oi_liq="'+Ctrl("liquidacion").GetXValue()+'"/>' , new ObjtectResult(),"S");
}

function CALL_VAL_VAREA()
{
	openNewFlowWait("NucleusRH.Base.Liquidacion.Variables.VariablesAcuPersona.flow","initialize",'<DATA oi="'+Ctrl("listFILTER").GetXValue()+'"/>', new ObjtectResult(),"L");
}

function BACK()
{
	FillArray(400);
	return true;
}
